My solution for haunting house problem

\#include \<vector\>
\# include<iostream\>
using namespace std;
int main() {
    int n;
    cin >> n;
    vector<vector<int>> vals(n, vector<int>(2, 0));
    for (int i = 0; i < n; i++) {
        cin >> vals[i][0] >> vals[i][1];

        // keeping number of people allowed
        // adding himself to allowed people
        vals[i][0]++;
        vals[i][1]++;
    }
    // Finally allowed_people[i] says how many people are okay to be in a group with i people. (i>=1)
    // start with noting down +1 and -1 in this vector as per list of ranges given
    vector<int> allowed_people(n+2, 0);
    int result = 0;
    for (int i = 0; i < n; i++) {
        // val[i][0] is start range and val[i][1]+1 is end of range so keeping values properly
        // so that in next iteration we get exact count. using min(n+1) as given range can cross these values
        allowed_people[min(n+1,vals[i][0])]++;
        allowed_people[min(n+1,vals[i][1]+1)]--;
    }
    int curcount = 0;
    for (int i = 1; i <=n ;i++) {
        // curcount says how many people are okay with group of i people including them selves
       // suppose 10 people are okay with group of 5 people then we can consider 5 for our result
       // suppose only 3 people okay with group of 7 people we can't consider 7 in result.
        curcount += allowed_people[i];
        if (curcount >= i) {
            result = max(result, i);
        }
    }
    cout << result << endl;
    return 0;
}

